import{_ as e,o as s,c as r,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Adaptadores de entrada","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/hexagonal/03-adaptadores-de-entrada.md","filePath":"full-stack/arquitectura/hexagonal/03-adaptadores-de-entrada.md","lastUpdated":1782521464000}'),t={name:"full-stack/arquitectura/hexagonal/03-adaptadores-de-entrada.md"};function l(i,a,n,d,p,c){return s(),r("div",null,[...a[0]||(a[0]=[o(`<h1 id="adaptadores-de-entrada" tabindex="-1">Adaptadores de entrada <a class="header-anchor" href="#adaptadores-de-entrada" aria-label="Permalink to &quot;Adaptadores de entrada&quot;">​</a></h1><p>Los adaptadores de entrada permiten que el mundo exterior ejecute casos de uso.</p><h2 id="tipos-habituales" tabindex="-1">Tipos habituales <a class="header-anchor" href="#tipos-habituales" aria-label="Permalink to &quot;Tipos habituales&quot;">​</a></h2><ul><li>Controladores REST.</li><li>GraphQL resolvers.</li><li>Consumers de eventos.</li><li>Jobs programados.</li><li>CLI commands.</li><li>Webhooks.</li></ul><h2 id="responsabilidades" tabindex="-1">Responsabilidades <a class="header-anchor" href="#responsabilidades" aria-label="Permalink to &quot;Responsabilidades&quot;">​</a></h2><p>Un adaptador de entrada debe:</p><ul><li>Leer datos externos.</li><li>Validar formato basico.</li><li>Traducir a comando interno.</li><li>Llamar al puerto o caso de uso.</li><li>Traducir la respuesta.</li><li>Mapear errores al protocolo correspondiente.</li></ul><h2 id="ejemplo-rest" tabindex="-1">Ejemplo REST <a class="header-anchor" href="#ejemplo-rest" aria-label="Permalink to &quot;Ejemplo REST&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /orders/{id}/confirm</span></span>
<span class="line"><span>  -&gt; ConfirmOrderController</span></span>
<span class="line"><span>  -&gt; ConfirmOrderCommand</span></span>
<span class="line"><span>  -&gt; ConfirmOrderUseCase</span></span></code></pre></div><p>El controlador no confirma el pedido. Solo traduce HTTP a una intencion interna.</p><h2 id="ejemplo-consumer" tabindex="-1">Ejemplo consumer <a class="header-anchor" href="#ejemplo-consumer" aria-label="Permalink to &quot;Ejemplo consumer&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PaymentCaptured event</span></span>
<span class="line"><span>  -&gt; PaymentCapturedConsumer</span></span>
<span class="line"><span>  -&gt; ConfirmPaidOrderCommand</span></span>
<span class="line"><span>  -&gt; ConfirmPaidOrderUseCase</span></span></code></pre></div><p>El consumer no deberia filtrar detalles del broker hacia el caso de uso.</p><h2 id="errores" tabindex="-1">Errores <a class="header-anchor" href="#errores" aria-label="Permalink to &quot;Errores&quot;">​</a></h2><p>Cada protocolo traduce errores de forma distinta:</p><ul><li>HTTP: status code y cuerpo JSON.</li><li>CLI: exit code y mensaje.</li><li>Kafka: retry, dead-letter o ack.</li><li>Cron: logs, metricas y alerta.</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>El adaptador no contiene reglas de negocio.</li><li>El caso de uso no recibe objetos del framework.</li><li>Los errores se traducen en el borde.</li><li>La validacion profunda vive dentro.</li><li>Hay tests para el mapeo de entrada.</li></ul>`,18)])])}const m=e(t,[["render",l]]);export{h as __pageData,m as default};
